package encapsulation;

public class Encapsulationeg {

	
		// TODO Auto-generated method stub
		private String name;
		private int age;
		private long phno;
		public String getName() {
			return name;
		}
		public void setName(String name) {
			this.name = name;
		}
		public int getAge() {
			return age;
		}
		public void setAge(int age) {
			this.age = age;
		}
		public long getPhno() {
			return phno;
		}
		public void setPhno(long phno) {
			this.phno = phno;
		}
	
		
		

	

}
